`$file = 'components/cat-ai-chat-interface.tsx'\n`$content = Get-Content -Path `$file -Raw\n\n# Insert markdownComponents just after ChatMessage interface\n`$insertionPoint = \"`nexport default function CatAiChatInterface\"\n`$markdownComponents = @'\n\nconst markdownComponents = {\n  h1: ({children}) => (\n    <h1 style={{\n      fontSize: '18px',\n      fontWeight: '600',\n      color: 'white',\n      marginTop: '20px',\n      marginBottom: '10px',\n      letterSpacing: '-0.02em',\n      lineHeight: '1.3'\n    }}>{children}</h1>\n  ),\n  h2: ({children}) => (\n    <h2 style={{\n      fontSize: '16px',\n      fontWeight: '600',\n      color: 'rgba(255,255,255,0.9)',\n      marginTop: '18px',\n      marginBottom: '8px',\n      letterSpacing: '-0.01em'\n    }}>{children}</h2>\n  ),\n  h3: ({children}) => (\n    <h3 style={{\n      fontSize: '14px',\n      fontWeight: '600',\n      color: 'rgba(255,255,255,0.85)',\n      marginTop: '14px',\n      marginBottom: '6px'\n    }}>{children}</h3>\n  ),\n  p: ({children}) => (\n    <p style={{\n      fontSize: '14px',\n      lineHeight: '1.8',\n      color: 'rgba(255,255,255,0.82)',\n      marginTop: '0',\n      marginBottom: '12px'\n    }}>{children}</p>\n  ),\n  strong: ({children}) => (\n    <strong style={{\n      fontWeight: '600',\n      color: 'white'\n    }}>{children}</strong>\n  ),\n  em: ({children}) => (\n    <em style={{\n      fontStyle: 'italic',\n      color: 'rgba(255,255,255,0.7)'\n    }}>{children}</em>\n  ),\n  ul: ({children}) => (\n    <ul style={{\n      paddingLeft: '0',\n      margin: '8px 0 12px 0',\n      listStyle: 'none'\n    }}>{children}</ul>\n  ),\n  ol: ({children}) => (\n    <ol style={{\n      paddingLeft: '20px',\n      margin: '8px 0 12px 0'\n    }}>{children}</ol>\n  ),\n  li: ({children}) => (\n    <li style={{\n      fontSize: '14px',\n      lineHeight: '1.75',\n      color: 'rgba(255,255,255,0.8)',\n      marginBottom: '6px',\n      paddingLeft: '16px',\n      position: 'relative',\n      display: 'flex',\n      alignItems: 'flex-start',\n      gap: '8px'\n    }}>\n      <span style={{\n        display: 'inline-block',\n        width: '5px',\n        height: '5px',\n        borderRadius: '50%',\n        background: '#3B82F6',\n        marginTop: '8px',\n        flexShrink: '0'\n      }}/>\n      <span>{children}</span>\n    </li>\n  ),\n  hr: () => (\n    <hr style={{\n      border: 'none',\n      borderTop: '1px solid rgba(255,255,255,0.08)',\n      margin: '16px 0'\n    }}/>)\n  ),\n  blockquote: ({children}) => (\n    <blockquote style={{\n      borderLeft: '2px solid #3B82F6',\n      paddingLeft: '14px',\n      margin: '12px 0',\n      color: 'rgba(255,255,255,0.6)',\n      fontSize: '14px',\n      fontStyle: 'italic'\n    }}>{children}</blockquote>\n  ),\n  code: ({inline, children}) => inline ? (\n    <code style={{\n      background: 'rgba(59,130,246,0.15)',\n      border: '1px solid rgba(59,130,246,0.2)',\n      borderRadius: '4px',\n      padding: '1px 6px',\n      fontSize: '13px',\n      color: '#93C5FD',\n      fontFamily: 'monospace'\n    }}>{children}</code>\n  ) : (\n    <pre style={{\n      background: 'rgba(255,255,255,0.05)',\n      border: '1px solid rgba(255,255,255,0.08)',\n      borderRadius: '8px',\n      padding: '14px 16px',\n      overflow: 'auto',\n      margin: '12px 0'\n    }}>\n      <code style={{\n        fontSize: '13px',\n        color: 'rgba(255,255,255,0.8)',\n        fontFamily: 'monospace',\n        lineHeight: '1.6'\n      }}>{children}</code>\n    </pre>\n  ),\n}\n'@\n\n# Replace {msg.answer} with ReactMarkdown rendering\n`$content = `$content -replace '                        \{msg\.answer\}', '                        <ReactMarkdown components={markdownComponents}>`n                          {msg.answer}`n                        </ReactMarkdown>'\n\nSet-Content -Path `$file -Value `$content -NoNewline\nWrite-Host 'Markdown integration complete!'\n"